export function formatValue(value, enableTimePicker, timeZone?, mode?) {
	if (isRangeMode(value) && Array.isArray(value)) {
		const hasUndefined = value.includes(undefined);
		const hasEmptyString = value.every(item => item === '');
		const isEmpty = value.length === 0;

		// Для rangeSplit режима возвращаем массив
		if (mode === 'rangeSplit') {
			// Если массив пустой, возвращаем массив с двумя пустыми строками
			if (isEmpty) {
				return ['', ''];
			}
			return value.map(item => getInputValue(item, enableTimePicker, timeZone));
		}

		if (hasEmptyString) {
			return value.map(item => getInputValue(item, enableTimePicker, timeZone)).join(EMPTY_DATE);
		}

		if (!hasUndefined) {
			return value.map(item => getInputValue(item, enableTimePicker, timeZone)).join(RANGE_DELIMETER);
		}

		return '';
	}

	return getInputValue(value, enableTimePicker, timeZone);
}
